/**
 * Vite plugin for talky-heads-sdk.
 * Automatically copies bundled avatar assets to public/avatars/ on dev/build.
 *
 * Usage:
 *   // vite.config.ts
 *   import { talkyHeadsPlugin } from 'talky-heads-sdk/vite';
 *   export default defineConfig({
 *     plugins: [react(), talkyHeadsPlugin()],
 *   });
 */

import fs from "fs";
import path from "path";
import type { Plugin } from "vite";

export interface TalkyHeadsPluginOptions {
    /**
     * Destination folder relative to project root.
     * Default: "public/avatars"
     */
    destDir?: string;
    /**
     * Whether to copy assets. Set to false to disable.
     * Default: true
     */
    copyAssets?: boolean;
}

/**
 * Copies the bundled Lucy avatar from node_modules to public/avatars/
 * so it's served at /avatars/Lucy automatically.
 */
export function talkyHeadsPlugin(options: TalkyHeadsPluginOptions = {}): Plugin {
    const { destDir = "public/avatars", copyAssets = true } = options;

    function copyAvatarAssets(root: string) {
        if (!copyAssets) return;

        // Find the installed package location
        const packagePaths = [
            path.join(root, "node_modules", "talky-heads-sdk", "assets", "avatars"),
            // Monorepo / workspace scenarios
            path.join(root, "..", "node_modules", "talky-heads-sdk", "assets", "avatars"),
            path.join(root, "..", "..", "node_modules", "talky-heads-sdk", "assets", "avatars"),
        ];

        let srcDir: string | null = null;
        for (const p of packagePaths) {
            if (fs.existsSync(p)) {
                srcDir = p;
                break;
            }
        }

        if (!srcDir) {
            console.warn("[talky-heads] Could not find avatar assets in node_modules. Skipping copy.");
            return;
        }

        const dest = path.join(root, destDir);
        const lucySrc = path.join(srcDir, "Lucy");
        const lucyDest = path.join(dest, "Lucy");

        if (!fs.existsSync(lucySrc)) {
            console.warn("[talky-heads] Lucy avatar not found in package assets. Skipping copy.");
            return;
        }

        // Skip if already exists and has content
        if (fs.existsSync(lucyDest) && fs.existsSync(path.join(lucyDest, "sprite_manifest.json"))) {
            console.log("[talky-heads] Lucy avatar already in public/avatars/Lucy");
            return;
        }

        // Copy recursively
        fs.mkdirSync(lucyDest, { recursive: true });
        copyDirSync(lucySrc, lucyDest);
        console.log("[talky-heads] Copied Lucy avatar to", lucyDest);
    }

    return {
        name: "talky-heads-plugin",
        configResolved(config) {
            copyAvatarAssets(config.root);
        },
    };
}

function copyDirSync(src: string, dest: string) {
    fs.mkdirSync(dest, { recursive: true });
    for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
        const srcPath = path.join(src, entry.name);
        const destPath = path.join(dest, entry.name);
        if (entry.isDirectory()) {
            copyDirSync(srcPath, destPath);
        } else {
            fs.copyFileSync(srcPath, destPath);
        }
    }
}

export default talkyHeadsPlugin;
